// nav-guard.js
// Purpose: if the main site's index.html nav is ever regenerated by another
// process and the breath-sounds link is dropped, this script re-inserts it
// on page load. This file lives in breath-sounds/ and is not touched by the
// main site's health-content publishing process.
(function () {
  function ensureBreathSoundsNav() {
    if (document.getElementById('nav-breath')) return; // already present
    var link = document.createElement('a');
    link.href = 'breath-sounds/index.html';
    link.id = 'nav-breath';
    link.textContent = String.fromCodePoint(0x1FAC1) + ' 呼吸音教學';
    // Anchor next to the health-education link, which has stayed stable
    // even when the nav container's class name changed (.main-nav -> .nav-r).
    var healthLink = document.getElementById('nav-health');
    if (healthLink && healthLink.parentNode) {
      healthLink.insertAdjacentElement('afterend', link);
      return;
    }
    // Fallback: common nav container selectors
    var nav = document.querySelector('.main-nav') || document.querySelector('.nav-r') || document.querySelector('nav');
    if (nav) nav.appendChild(link);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', ensureBreathSoundsNav);
  } else {
    ensureBreathSoundsNav();
  }
})();
